// Upload flow
// 1. Client POST /api/upload-init → server generates presigned PUT URL
func handleUploadInit(w http.ResponseWriter, r *http.Request) {
    key := generateS3Key(userID, filename)

    presignClient := s3.NewPresignClient(s3Client)
    req, _ := presignClient.PresignPutObject(ctx, &s3.PutObjectInput{
        Bucket: &bucket,
        Key:    &key,
    }, s3.WithPresignExpires(15*time.Minute))

    json.NewEncoder(w).Encode(map[string]string{
        "uploadUrl": req.URL,
        "key":       key,
    })
}

// 2. Client PUT directly to S3 using the presigned URL (server not involved)
// 3. Client POST /api/upload-finalize → server records metadata in SQLite
func handleUploadFinalize(w http.ResponseWriter, r *http.Request) {
    // Save file record to SQLite
    db.Create(&File{
        Name:     filename,
        S3Key:    key,
        ParentID: parentID,
        UserID:   userID,
        Size:     size,
    })
    cache.InvalidateFolder(userID, parentID)
}

// Cache key: userID:folderID
// Invalidation: targeted per folder, not global flush

type Cache struct {
    mu    sync.RWMutex
    store map[string]CacheEntry
}

func (c *Cache) Get(userID, folderID string) ([]File, bool) {
    c.mu.RLock()
    defer c.mu.RUnlock()
    key := userID + ":" + folderID
    entry, ok := c.store[key]
    if !ok || time.Now().After(entry.ExpiresAt) {
        return nil, false
    }
    return entry.Files, true
}

func (c *Cache) InvalidateFolder(userID, folderID string) {
    c.mu.Lock()
    defer c.mu.Unlock()
    delete(c.store, userID+":"+folderID)
}

// Rate limiter middleware — token bucket per IP
func rateLimitMiddleware(next http.HandlerFunc, rps int) http.HandlerFunc {
    limiters := sync.Map{}

    return func(w http.ResponseWriter, r *http.Request) {
        ip := r.RemoteAddr
        limiter, _ := limiters.LoadOrStore(ip,
            rate.NewLimiter(rate.Limit(rps), rps*2))

        if !limiter.(*rate.Limiter).Allow() {
            http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
            return
        }
        next(w, r)
    }
}

// Cleanup worker — runs every hour
func startCleanupWorker(db *gorm.DB, s3Client *s3.Client) {
    ticker := time.NewTicker(1 * time.Hour)
    go func() {
        for range ticker.C {
            var expired []File
            cutoff := time.Now().Add(-30 * 24 * time.Hour)
            db.Where("deleted_at < ? AND trashed = true", cutoff).Find(&expired)

            for _, f := range expired {
                // Delete from S3
                s3Client.DeleteObject(ctx, &s3.DeleteObjectInput{
                    Bucket: &bucket,
                    Key:    &f.S3Key,
                })
                // Delete from SQLite
                db.Delete(&f)
            }
        }
    }()
}

// Auth middleware
func authMiddleware(next http.HandlerFunc) http.HandlerFunc {
    return func(w http.ResponseWriter, r *http.Request) {
        token := strings.TrimPrefix(r.Header.Get("Authorization"), "Bearer ")

        claims, err := jwt.ParseWithClaims(token, &Claims{},
            func(t *jwt.Token) (interface{}, error) {
                return []byte(os.Getenv("JWT_SECRET")), nil
            })

        if err != nil || !claims.Valid {
            http.Error(w, "Unauthorized", http.StatusUnauthorized)
            return
        }

        // Inject user context
        ctx := context.WithValue(r.Context(), "user", claims.Claims)
        next(w, r.WithContext(ctx))
    }
}

// Storage client init — reads from env vars at startup
func NewS3Client() *s3.Client {
    cfg, _ := config.LoadDefaultConfig(ctx,
        config.WithRegion(os.Getenv("S3_REGION")),
        config.WithCredentialsProvider(
            credentials.NewStaticCredentialsProvider(
                os.Getenv("AWS_ACCESS_KEY_ID"),
                os.Getenv("AWS_SECRET_ACCESS_KEY"),
                "",
            ),
        ),
    )

    return s3.NewFromConfig(cfg, func(o *s3.Options) {
        // Override endpoint for R2 or MinIO
        if endpoint := os.Getenv("S3_ENDPOINT"); endpoint != "" {
            o.BaseEndpoint = aws.String(endpoint)
            o.UsePathStyle = true // required for MinIO
        }
    })
}
